 1	import type { FC } from 'react';
 2	import InventoryNotReachable from 'src/modules/Providers/views/list/components/InventoryNotReachable';
 3	import { useProvidersInventoryIsLive } from 'src/overview/hooks/useProvidersInventoryIsLive';
 4	
 5	import {
 6	  Button,
 7	  ButtonVariant,
 8	  PageSection,
 9	  PageSectionVariants,
10	  Split,
11	  SplitItem,
12	  Title,
13	} from '@patternfly/react-core';
14	import { TELEMETRY_EVENTS } from '@utils/analytics/constants';
15	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
16	import { useForkliftTranslation } from '@utils/i18n';
17	
18	type HeaderTitleProps = {
19	  isDrawerOpen: boolean;
20	  setIsDrawerOpen: (isOpen: boolean) => void;
21	};
22	
23	const HeaderTitle: FC<HeaderTitleProps> = ({ isDrawerOpen, setIsDrawerOpen }) => {
24	  const { loadError: inventoryLivelinessError } = useProvidersInventoryIsLive({});
25	  const { t } = useForkliftTranslation();
26	  const { trackEvent } = useForkliftAnalytics();
27	
28	  return (
29	    <>
30	      <PageSection variant={PageSectionVariants.light}>
31	        <Split hasGutter style={{ alignItems: 'baseline' }}>
32	          <SplitItem isFilled>
33	            <Title headingLevel="h1">{t('Migration Toolkit for Virtualization')}</Title>
34	          </SplitItem>
35	          {isDrawerOpen ? undefined : (
36	            <Button
37	              variant={ButtonVariant.link}
38	              isInline
39	              onClick={() => {
40	                trackEvent(TELEMETRY_EVENTS.TIPS_AND_TRICKS_CLICKED);
41	                setIsDrawerOpen(true);
42	              }}
43	            >
44	              {t('Tips and tricks')}
45	            </Button>
46	          )}
47	        </Split>
48	      </PageSection>
49	      {inventoryLivelinessError && (
50	        <PageSection variant="light">
51	          {[<InventoryNotReachable key="inventoryNotReachable" />]}
52	        </PageSection>
53	      )}
54	    </>
55	  );
56	};
57	
58	export default HeaderTitle;

